module top_module(
  input clk,
  input rst_n,
  input IRWrite,
  input [31:0] Instr_i,

  output [31:0] Instr_o
  );reg [31:0] unused_IR;
  always@(posedge clk or posedge rst_n)
  begin
    if (rst_n)
      unused_IR <= 32'h0;
    else
      begin
        if (IRWrite)
          unused_IR <= Instr_i;
      end
  end
  assign Instr_o = unused_IR;
endmodule
